import React, { useEffect, useState } from 'react';
import './Hero.css';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faAddressCard } from '@fortawesome/free-solid-svg-icons';
import { useNavigate } from 'react-router-dom';

function Hero() {
	const [goUp, setGoUp] = useState(false);
	const navigate = useNavigate();
	
	const handleRegisterClick = () => {
		navigate('/register');
	};
	useEffect(() => {
		const onPageScroll = () => {
			if (window.scrollY > 600) {
				setGoUp(true);
			} else {
				setGoUp(false);
			}
		};
		window.addEventListener('scroll', onPageScroll);

		return () => {
			window.removeEventListener('scroll', onPageScroll);
		};
	}, []);

	return (
		<div className="flowhero-section" id="flowherohero">
			<div className="about-image-content">
				{/* <div id="container">
					<div id="circle"></div>
					<div id="small-circle"></div>
					<div id="smaller-circle"></div>
					<div id="smallest-circle"></div>
				</div> */}
			</div>

			<div className="text-section">
					<p className="text-headline">{`What is FlowHero?`}</p>
					<h2 className="text-title" >{`Our in-house cloud solution designed to automate your company's workflows.`}</h2>

					<p className="text-descritpion">{`We can automate your complex business processes and functions using our easy to understand interface. Built on the cloud, concentrate on what your business do best and leave us the worry of data gathering and information delivery to your customers.`}</p>
					
					<h2 className="text-title-sub">{`What is the difference between workflows and modules?`}</h2>
					<p className="text-descritpion">{`Workflows are the steps undertaken to complete a task and give a result. In Flowhero, modules are subsets of workflows. Think of modules as forms that uses workflows as the underlying steps to make it run, provide the inputs, outputs and create the transaction the workflow is meant to do. Multiple modules can be created from one workflow, all with distinguishing document IDs but having the same input and outputs.`}</p>
				
					<h2 className="text-title-sub">{`What's the investment to setup Flowhero?`}</h2>
					<p className="text-descritpion">{`Flowhero is accessed via a browser. Let the worry of setting it up and maintaining to us. You just need to subscribe for a plan.`}</p>
					
					
					<button className="text-appointment-btn" style={{backgroundColor:'green'}} type="button" onClick={handleRegisterClick}>
						<FontAwesomeIcon icon={faAddressCard} /> {`REGISTER YOUR COMPANY`}
					</button>
				</div>

		</div>
	);
}

export default Hero;
